// Validate request: extract short_id, platform, caption, hashtags
const body = $input.first().json.body || {};
const shortId = body.short_id;
const platform = body.platform; // tiktok | instagram | youtube_shorts
const caption = body.caption || '';
const hashtags = body.hashtags || [];

if (!shortId) {
  throw new Error('Missing required field: short_id');
}

const validPlatforms = ['tiktok', 'instagram', 'youtube_shorts'];
if (!platform || !validPlatforms.includes(platform)) {
  throw new Error(`Invalid platform: ${platform}. Must be one of: ${validPlatforms.join(', ')}`);
}

return [{ json: { short_id: shortId, platform, caption, hashtags } }];

// Post to TikTok Content Posting API
const shortData = $('Read Short').first().json[0];
const renderData = $('Read Render').first().json[0] || {};
const validateData = $('Validate Request').first().json;
const caption = validateData.caption || shortData.tiktok_caption || shortData.caption || '';
const hashtags = validateData.hashtags || shortData.hashtags || [];
const fullCaption = caption + (hashtags.length ? ' ' + hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ') : '');

const videoUrl = renderData.file_url || shortData.portrait_drive_url;
if (!videoUrl) {
  return [{ json: { success: false, platform: 'tiktok', error: 'No video URL available', short_id: shortData.id } }];
}

const accessToken = process.env.TIKTOK_ACCESS_TOKEN;
if (!accessToken) {
  return [{ json: { success: false, platform: 'tiktok', error: 'TIKTOK_ACCESS_TOKEN not configured — skipping', short_id: shortData.id, skipped: true } }];
}

try {
  // Step 1: Init video upload
  const initResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://open.tiktokapis.com/v2/post/publish/video/init/',
    headers: {
      'Authorization': `Bearer ${accessToken}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      post_info: {
        title: fullCaption.substring(0, 150),
        privacy_level: 'PUBLIC_TO_EVERYONE',
        disable_duet: false,
        disable_comment: false,
        disable_stitch: false,
      },
      source_info: {
        source: 'PULL_FROM_URL',
        video_url: videoUrl,
      },
    }),
  });

  const publishId = initResp?.data?.publish_id || null;
  return [{ json: { success: true, platform: 'tiktok', post_id: publishId, short_id: shortData.id, caption: fullCaption } }];
} catch (e) {
  return [{ json: { success: false, platform: 'tiktok', error: e.message, short_id: shortData.id } }];
}

// Post to Instagram Graph API (Reels)
const shortData = $('Read Short').first().json[0];
const renderData = $('Read Render').first().json[0] || {};
const validateData = $('Validate Request').first().json;
const caption = validateData.caption || shortData.instagram_caption || shortData.caption || '';
const hashtags = validateData.hashtags || shortData.hashtags || [];
const fullCaption = caption + (hashtags.length ? '\n\n' + hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ') : '');

const videoUrl = renderData.file_url || shortData.portrait_drive_url;
if (!videoUrl) {
  return [{ json: { success: false, platform: 'instagram', error: 'No video URL available', short_id: shortData.id } }];
}

const accessToken = process.env.INSTAGRAM_ACCESS_TOKEN;
const igUserId = process.env.INSTAGRAM_USER_ID;
if (!accessToken || !igUserId) {
  return [{ json: { success: false, platform: 'instagram', error: 'INSTAGRAM_ACCESS_TOKEN or INSTAGRAM_USER_ID not configured — skipping', short_id: shortData.id, skipped: true } }];
}

try {
  // Step 1: Create media container (Reels)
  const createResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v19.0/${igUserId}/media`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      media_type: 'REELS',
      video_url: videoUrl,
      caption: fullCaption.substring(0, 2200),
      access_token: accessToken,
      share_to_feed: true,
    }),
  });

  const containerId = createResp?.id;
  if (!containerId) {
    return [{ json: { success: false, platform: 'instagram', error: 'Failed to create media container', short_id: shortData.id } }];
  }

  // Step 2: Wait for processing (poll status)
  let ready = false;
  for (let attempt = 0; attempt < 10; attempt++) {
    await new Promise(r => setTimeout(r, 5000));
    const statusResp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://graph.facebook.com/v19.0/${containerId}?fields=status_code&access_token=${accessToken}`,
    });
    if (statusResp?.status_code === 'FINISHED') { ready = true; break; }
    if (statusResp?.status_code === 'ERROR') {
      return [{ json: { success: false, platform: 'instagram', error: 'Media processing failed', short_id: shortData.id } }];
    }
  }

  if (!ready) {
    return [{ json: { success: false, platform: 'instagram', error: 'Media processing timed out', short_id: shortData.id } }];
  }

  // Step 3: Publish
  const publishResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v19.0/${igUserId}/media_publish`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ creation_id: containerId, access_token: accessToken }),
  });

  return [{ json: { success: true, platform: 'instagram', post_id: publishResp?.id || containerId, short_id: shortData.id, caption: fullCaption } }];
} catch (e) {
  return [{ json: { success: false, platform: 'instagram', error: e.message, short_id: shortData.id } }];
}

// Update shorts table with platform-specific posting result
const result = $input.first().json;
const platform = result.platform || $('Validate Request').first().json.platform;
const shortId = result.short_id || $('Validate Request').first().json.short_id;
const success = result.success;

const updateFields = {};
const now = new Date().toISOString();

if (platform === 'tiktok') {
  updateFields.tiktok_status = success ? 'published' : 'failed';
  if (success && result.post_id) updateFields.tiktok_post_id = result.post_id;
  if (success) updateFields.tiktok_published_at = now;
  if (result.caption) updateFields.tiktok_caption = result.caption;
} else if (platform === 'instagram') {
  updateFields.instagram_status = success ? 'published' : 'failed';
  if (success && result.post_id) updateFields.instagram_post_id = result.post_id;
  if (success) updateFields.instagram_published_at = now;
  if (result.caption) updateFields.instagram_caption = result.caption;
} else if (platform === 'youtube_shorts') {
  updateFields.youtube_shorts_status = success ? 'published' : 'failed';
  if (result.youtube_video_id) updateFields.youtube_shorts_video_id = result.youtube_video_id;
  if (success) updateFields.youtube_shorts_published_at = now;
}

// PATCH shorts table
await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${process.env.SUPABASE_URL}/rest/v1/shorts?id=eq.${shortId}`,
  headers: {
    'apikey': process.env.SUPABASE_ANON_KEY,
    'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation',
  },
  body: JSON.stringify({ ...updateFields, updated_at: now }),
});

return [{ json: { short_id: shortId, platform, success, post_id: result.post_id || null, fields_updated: Object.keys(updateFields) } }];

// Handle error: update short status to failed
const platform = $('Validate Request').first().json.platform;
const shortId = $('Validate Request').first().json.short_id;
const errorMsg = $input.first().json?.message || 'Unknown error';

const updateFields = {};
if (platform === 'tiktok') updateFields.tiktok_status = 'failed';
else if (platform === 'instagram') updateFields.instagram_status = 'failed';
else if (platform === 'youtube_shorts') updateFields.youtube_shorts_status = 'failed';

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${process.env.SUPABASE_URL}/rest/v1/shorts?id=eq.${shortId}`,
    headers: {
      'apikey': process.env.SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
    },
    body: JSON.stringify({ ...updateFields, updated_at: new Date().toISOString() }),
  });
} catch (e) { /* best effort */ }

return [{ json: { short_id: shortId, platform, error: errorMsg, status: 'failed' } }];
